    hint: "You don't have permission to access this channel. Check your authentication.",
    docs: "https://docs.flywheel.dev/websocket#authentication",
  },

  CURSOR_EXPIRED: {
    hint: "The cursor has expired. Reconnect without a cursor to get the latest messages.",
    example: { type: "subscribe", channel: "agent:output:agent-123" },
  },

